// ─── APP ─────────────────────────────────────────────────────────────────────
export default function Portfolio() {
  const [activeSection, setActiveSection] = useState("inicio");

  useEffect(() => {
    const sections = ["inicio", "sobre", "habilidades", "formacao", "projetos", "contato"];
    const obs = new IntersectionObserver(
      entries => { entries.forEach(e => { if (e.isIntersecting) setActiveSection(e.target.id); }); },
      { threshold: 0.3 }
    );
    sections.forEach(id => { const el = document.getElementById(id); if (el) obs.observe(el); });
    return () => obs.disconnect();
  }, []);

  return (
    <>
      <NavBar active={activeSection} />
      <main>
        <HeroSection />
        <AboutSection />
        <SkillsSection />
        <EducationSection />
        <ProjectsSection />
        <ContactSection />
      </main>
      <footer style={{ padding: "2rem", borderTop: "1px solid rgba(255,255,255,0.06)", textAlign: "center", background: "#0a0a0a" }}>
        <p style={{ fontFamily: "'DM Mono', monospace", fontSize: "0.7rem", color: "#4b5563" }}>
          Desenvolvido com ♥ por <span style={{ color: "#059669" }}>Matheus Silva Braga</span> · {new Date().getFullYear()}
        </p>
      </footer>
    </>
  );
}